log('并行深度分析核心源文件...')

// 定义需要深度分析的核心文件（根据重要性分组）
const criticalFiles = [
  'parser/core_parser.cpp',           // 主入口
  'android/art/runtime/mirror/class.h',   // ART Class 镜像
  'android/art/runtime/mirror/object.h',  // ART Object 镜像
  'android/art/runtime/mirror/string.h',  // ART String 镜像
]

const commandFiles = [
  'parser/command/cmd_class.cpp',     // class 命令
  'parser/command/cmd_space.cpp',     // space 命令
  'parser/command/cmd_thread.cpp',    // thread 命令
  'parser/command/cmd_top.cpp',       // top 命令
]

const coreFiles = [
  'core/core.h',                      // 核心接口
  'android/android.cpp',              // Android 版本检测
]

const allFiles = [...criticalFiles, ...commandFiles, ...coreFiles]

const fileAnalyses = await pipeline(
  allFiles,
  // Stage 1: 并行读取并分析每个文件
  async (file) => {
    return await agent(
      `深度分析文件: ${file}

       任务：
       1. 提取主要类、结构体、函数定义
       2. 识别关键算法和数据结构
       3. 分析与其他模块的依赖关系
       4. 提取代码注释中的设计决策和领域知识
       5. 识别使用的设计模式（如命令模式、工厂模式）

       特别关注：
       - ART 运行时对象的内存布局
       - HeapReference 的 32 位压缩机制
       - 命令的注册和执行流程
       - ELF 文件解析逻辑

       输出结构化的文件分析报告`,
      {
        label: `分析 ${file.split('/').pop()}`,
        phase: '文件批量分析',
        schema: {
          type: 'object',
          properties: {
            filePath: { type: 'string' },
            fileType: { type: 'string' },
            mainClasses: {
              type: 'array',
              items: {
                type: 'object',
                properties: {
                  name: { type: 'string' },
                  purpose: { type: 'string' },
                  keyMethods: { type: 'array', items: { type: 'string' } }
                }
              }
            },
            keyAlgorithms: { type: 'array', items: { type: 'string' } },
            designPatterns: { type: 'array', items: { type: 'string' } },
            dependencies: { type: 'array', items: { type: 'string' } },
            insights: { type: 'string' }
          },
          required: ['filePath', 'mainClasses', 'insights']
        }
      }
    )
  }
)

const validAnalyses = fileAnalyses.filter(Boolean)
log(`✓ 完成 ${validAnalyses.length}/${allFiles.length} 个文件的深度分析`)

// ============================================================
// 阶段 5: 知识整合
// ============================================================
phase('知识整合')
log('整合所有分析结果，生成统一知识报告...')

const knowledgeReport = await agent(
  `整合以下分析结果，生成 OpenCoreAnalysisKit 的完整知识报告:

   输入数据：
   1. 项目扫描: ${JSON.stringify(scanResult, null, 2)}
   2. 架构分析: ${JSON.stringify(archResult, null, 2)}
   3. 领域分析: ${JSON.stringify(domainResult, null, 2)}
   4. 文件分析: ${JSON.stringify(validAnalyses, null, 2)}

   任务：
   1. 生成项目整体概览
   2. 总结关键架构决策和设计模式
   3. 提炼核心领域知识点
   4. 识别代码热点和关键路径
   5. 生成学习路径建议（新手如何快速上手）
   6. 列出潜在改进点和技术债务

   输出结构化的知识报告`,
  {
    label: '生成知识报告',
    schema: {
      type: 'object',
      properties: {
        overview: { type: 'string' },
        architectureHighlights: { type: 'array', items: { type: 'string' } },
        domainKnowledge: { type: 'array', items: { type: 'string' } },
        codeHotspots: { type: 'array', items: { type: 'string' } },
        learningPath: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              step: { type: 'number' },
              title: { type: 'string' },
              focus: { type: 'string' },
              files: { type: 'array', items: { type: 'string' } }
            }
          }
        },
        improvements: { type: 'array', items: { type: 'string' } }
      },
      required: ['overview', 'architectureHighlights', 'learningPath']
    }
  }
)

log(`✓ 知识整合完成`)

// ============================================================
// 返回完整的探索结果
// ============================================================
return {
  projectScan: scanResult,
  architecture: archResult,
  domain: domainResult,
  fileAnalyses: validAnalyses,
  knowledgeReport: knowledgeReport,

  // 生成摘要
  summary: {
    totalFiles: scanResult.fileCount,
    layersIdentified: archResult.layers.length,
    domainsAnalyzed: domainResult.domains.length,
    filesDeepDived: validAnalyses.length,
    keyInsights: knowledgeReport.architectureHighlights.slice(0, 5),
    nextSteps: [
      '查看生成的 docs/exploration/ 目录下的详细报告',
      '使用 claude-mem 构建可查询的知识库',
