#include "logger/log.h"
#include "android.h"
#include "command/android/cmd_space.h"
#include "command/android/verify.h"
#include "api/core.h"
#include "runtime/runtime.h"
#include "runtime/gc/heap.h"
#include "runtime/gc/space/space.h"
#include "runtime/gc/space/large_object_space.h"
#include <unistd.h>
#include <getopt.h>

int SpaceCommand::prepare(int argc, char* const argv[]) {
    if (!CoreApi::IsReady() || !Android::IsSdkReady())
        return Command::FINISH;

    options.check = false;
    options.flag = 0;
    options.verify = 0;

    int opt;
    int option_index = 0;
    optind = 0; // reset
    static struct option long_options[] = {
        {"check",      no_argument,       0,  'c'},
        {"full-check", no_argument,       0,  'f'},
        {"app",        no_argument,       0,   1 },
        {"zygote",     no_argument,       0,   2 },
        {"image",      no_argument,       0,   3 },
        {"fake",       no_argument,       0,   4 },
        {0,            0,                 0,   0 },
    };

    while ((opt = getopt_long(argc, argv, "cf",
                long_options, &option_index)) != -1) {
        switch (opt) {
            case 'c':
                options.check = true;
                break;
            case 'f':
                options.check = true;
                options.verify = JavaVerify::CHECK_FULL_BAD_OBJECT
                              | JavaVerify::CHECK_FULL_CONFLICT_METHOD
                              | JavaVerify::CHECK_FULL_REUSE_DEX_PC_PTR
                              | JavaVerify::CHECK_FULL_U_EXTENDS_RECORD;
                break;
            case 1:
                options.flag |= Android::EACH_APP_OBJECTS;
                break;
            case 2:
                options.flag |= Android::EACH_ZYGOTE_OBJECTS;
                break;
            case 3:
                options.flag |= Android::EACH_IMAGE_OBJECTS;
                break;
            case 4:
                options.flag |= Android::EACH_FAKE_OBJECTS;
                break;
        }
    }
    options.optind = optind;

    if (!options.flag) {
        options.flag |= Android::EACH_APP_OBJECTS;
        options.flag |= Android::EACH_ZYGOTE_OBJECTS;
        options.flag |= Android::EACH_IMAGE_OBJECTS;
        options.flag |= Android::EACH_FAKE_OBJECTS;
    }

    Android::Prepare();
    return Command::ONCHLD;
}

int SpaceCommand::main(int argc, char* const argv[]) {
    if (options.check) {
        JavaVerify verify;
        verify.init(options.verify, options.flag);
        auto callback = [&](art::mirror::Object& object) -> bool {
            if (verify.isEnabled()) verify.verify(object);
            return false;
        };
        Android::ForeachObjects(callback, options.flag, true);
        verify.verifyMethods();
    } else {
        art::Runtime& runtime = art::Runtime::Current();
        art::gc::Heap& heap = runtime.GetHeap();

        LOGI(ANSI_COLOR_LIGHTRED "TYPE   REGION                  ADDRESS             NAME\n" ANSI_COLOR_RESET);
        for (const auto& space : heap.GetContinuousSpaces()) {
            art::gc::space::ContinuousSpace* sp = space.get();
            LOGI(" %2d  " ANSI_COLOR_LIGHTCYAN "[0x%" PRIx64 ", 0x%" PRIx64 ")  " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "  " ANSI_COLOR_LIGHTGREEN "%s\n" ANSI_COLOR_RESET,
                    sp->GetType(), sp->Begin(), sp->End(), sp->Ptr(), sp->GetName());
        }

        for (const auto& space : heap.GetDiscontinuousSpaces()) {
            art::gc::space::DiscontinuousSpace* dsp = space.get();
            if (space->IsLargeObjectSpace()) {
                art::gc::space::LargeObjectSpace *sp = reinterpret_cast<art::gc::space::LargeObjectSpace *>(dsp);
                LOGI(" %2d  " ANSI_COLOR_LIGHTCYAN "[0x%" PRIx64 ", 0x%" PRIx64 ")  " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "  " ANSI_COLOR_LIGHTGREEN "%s\n" ANSI_COLOR_RESET,
                        sp->GetType(), sp->Begin(), sp->End(), sp->Ptr(), sp->GetName());
            } else {
                LOGI(" %2d  [0x0, 0x0)  0x%" PRIx64 "  %s\n", space->GetType(), space->Ptr(), space->GetName());
            }
        }
    }
    return 0;
}

void SpaceCommand::usage() {
    LOGI("Usage: space [OPTION] [TYPE]\n");
    LOGI("Option:\n");
    LOGI("    -c, --check        check java space bad object.\n");
    LOGI("    -f, --full-check   check java space moreinfo.\n");
    LOGI("Type: {--app, --zygote, --image, --fake}\n");
    ENTER();
    LOGI("core-parser> space\n");
    LOGI("TYPE   REGION                  ADDRESS             NAME\n");
    LOGI("  5  [0x12c00000, 0x2ac00000)  0x75db0d608820  main space (region space)\n");
    LOGI("  0  [0x70209000, 0x7033d840)  0x75dbad608430  /system/framework/x86_64/boot.art\n");
    LOGI("  0  [0x704c2000, 0x704dfc88)  0x75dbad6086f0  /system/framework/x86_64/boot-core-libart.art\n");
    LOGI("  ...\n");
    ENTER();
    LOGI("core-parser> space --check --app\n");
    LOGI("ERROR: Region:[0x12c00000, 0x12c00018) main space (region space) has bad object!!\n");
}

content.text:
非常好的问题！让我根据代码和之前的知识分析，详细解释 `space` 命令的实现：

## `space` 命令实现详解

### 一、核心功能

`space` 命令用于显示和验证 Android ART 运行时的 Java 堆空间（heap spaces）。它有两个主要模式：

1. **显示模式**（默认）：列出所有内存空间及其地址范围
2. **检查模式**（`--check`）：验证堆中对象的完整性

### 二、实现架构

```mermaid
graph TB
    A[space 命令] --> B{check 标志?}
    B -->|否| C[显示模式]
    B -->|是| D[验证模式]

    C --> E[获取 Runtime]
    E --> F[获取 Heap]
    F --> G[遍历 ContinuousSpaces]
    F --> H[遍历 DiscontinuousSpaces]
    G --> I[显示空间信息]
    H --> I

    D --> J[初始化 JavaVerify]
    J --> K[ForeachObjects]
    K --> L[验证每个对象]
    L --> M[verifyMethods]

    style C fill:#e1f5ff
    style D fill:#f3e5f5
```

### 三、代码结构分析

#### 3.1 `prepare()` 方法 - 参数解析

```cpp
int SpaceCommand::prepare(int argc, char* const argv[]) {
    // 1. 前置检查
    if (!CoreApi::IsReady() || !Android::IsSdkReady())
        return Command::FINISH;  // 未加载 core 或未检测到 Android SDK

    // 2. 初始化选项
    options.check = false;       // 是否启用检查模式
    options.flag = 0;            // 对象类型过滤标志
    options.verify = 0;          // 验证选项标志

    // 3. 解析命令行参数
    static struct option long_options[] = {
        {"check",      no_argument, 0, 'c'},  // -c: 基础检查
        {"full-check", no_argument, 0, 'f'},  // -f: 完整检查
        {"app",        no_argument, 0,  1 },  // --app: 只检查应用对象
        {"zygote",     no_argument, 0,  2 },  // --zygote: 只检查 zygote 对象
        {"image",      no_argument, 0,  3 },  // --image: 只检查 image 对象
        {"fake",       no_argument, 0,  4 },  // --fake: 只检查伪造对象
    };

    // 4. 处理参数
    while ((opt = getopt_long(argc, argv, "cf", long_options, &option_index)) != -1) {
        switch (opt) {
            case 'c':
                options.check = true;
                break;
            case 'f':
                options.check = true;
                // 启用所有验证选项
                options.verify = JavaVerify::CHECK_FULL_BAD_OBJECT
                              | JavaVerify::CHECK_FULL_CONFLICT_METHOD
                              | JavaVerify::CHECK_FULL_REUSE_DEX_PC_PTR
                              | JavaVerify::CHECK_FULL_U_EXTENDS_RECORD;
                break;
            case 1: options.flag |= Android::EACH_APP_OBJECTS; break;
            case 2: options.flag |= Android::EACH_ZYGOTE_OBJECTS; break;
            case 3: options.flag |= Android::EACH_IMAGE_OBJECTS; break;
            case 4: options.flag |= Android::EACH_FAKE_OBJECTS; break;
        }
    }

    // 5. 默认行为：如果没有指定类型，遍历所有类型
    if (!options.flag) {
        options.flag = Android::EACH_APP_OBJECTS
                     | Android::EACH_ZYGOTE_OBJECTS
                     | Android::EACH_IMAGE_OBJECTS
                     | Android::EACH_FAKE_OBJECTS;
    }

    // 6. 准备 Android 运行时
    Android::Prepare();

    // 7. 返回 ONCHLD 表示在子进程中执行（防止崩溃影响主进程）
    return Command::ONCHLD;
}
```

**关键设计**：
- 使用 `ONCHLD` 模式在子进程执行，避免堆遍历时崩溃影响 REPL
- 默认启用所有对象类型，用户可通过标志过滤

#### 3.2 `main()` 方法 - 核心逻辑

##### 模式 1: 验证模式（`--check`）

```cpp
if (options.check) {
    // 1. 创建验证器
    JavaVerify verify;
    verify.init(options.verify, options.flag);

    // 2. 定义验证回调
    auto callback = [&](art::mirror::Object& object) -> bool {
        if (verify.isEnabled()) 
            verify.verify(object);  // 验证单个对象
        return false;  // 返回 false 继续遍历
    };

    // 3. 遍历所有对象
    Android::ForeachObjects(callback, options.flag, true);

    // 4. 验证方法（检查冲突、复用等）
    verify.verifyMethods();
}
```

**验证内容**（`JavaVerify` 类）：
- `CHECK_FULL_BAD_OBJECT`: 检查对象引用有效性
- `CHECK_FULL_CONFLICT_METHOD`: 检查方法冲突
- `CHECK_FULL_REUSE_DEX_PC_PTR`: 检查 DEX PC 指针复用
- `CHECK_FULL_U_EXTENDS_RECORD`: Android U 特定检查

##### 模式 2: 显示模式（默认）

```cpp
else {
    // 1. 获取 ART Runtime 和 Heap
    art::Runtime& runtime = art::Runtime::Current();
    art::gc::Heap& heap = runtime.GetHeap();

    // 2. 显示表头
    LOGI(ANSI_COLOR_LIGHTRED "TYPE   REGION                  ADDRESS             NAME\n" ANSI_COLOR_RESET);

    // 3. 遍历连续空间
    for (const auto& space : heap.GetContinuousSpaces()) {
        art::gc::space::ContinuousSpace* sp = space.get();
        LOGI(" %2d  " ANSI_COLOR_LIGHTCYAN "[0x%" PRIx64 ", 0x%" PRIx64 ")  " 
             ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "  " 
             ANSI_COLOR_LIGHTGREEN "%s\n" ANSI_COLOR_RESET,
             sp->GetType(),    // 空间类型编号
             sp->Begin(),      // 起始地址
             sp->End(),        // 结束地址
             sp->Ptr(),        // Space 对象的虚拟地址
             sp->GetName());   // 空间名称
    }

    // 4. 遍历不连续空间
    for (const auto& space : heap.GetDiscontinuousSpaces()) {
        art::gc::space::DiscontinuousSpace* dsp = space.get();

        // 特殊处理 LargeObjectSpace（有地址范围）
        if (space->IsLargeObjectSpace()) {
            art::gc::space::LargeObjectSpace *sp = 
                reinterpret_cast<art::gc::space::LargeObjectSpace *>(dsp);
            LOGI(" %2d  [0x%" PRIx64 ", 0x%" PRIx64 ")  0x%" PRIx64 "  %s\n",
                 sp->GetType(), sp->Begin(), sp->End(), sp->Ptr(), sp->GetName());
        } else {
            // 普通不连续空间（无统一地址范围）
            LOGI(" %2d  [0x0, 0x0)  0x%" PRIx64 "  %s\n", 
                 space->GetType(), space->Ptr(), space->GetName());
        }
    }
}
```

### 四、空间类型详解

根据 `docs/exploration/03-domain-knowledge.md`，堆空间分为两大类：

#### ContinuousSpace（连续空间）

```
TYPE  REGION                    ADDRESS             NAME
 5    [0x12c00000, 0x2ac00000)  0x75db0d608820     main space (region space)
 0    [0x70209000, 0x7033d840)  0x75dbad608430     /system/framework/x86_64/boot.art
 1    [0x0, 0x0)                0x75db0d6088e0     zygote space
```

**类型枚举**：
- `0`: ImageSpace - boot.art 预加载的系统对象
- `1`: ZygoteSpace - Zygote 进程的共享对象
- `5`: RegionSpace - 应用主堆（支持并发 GC）
- `6`: MallocSpace - malloc 分配的堆空间

**特点**：
- 有连续的 `[Begin, End)` 地址范围
- 可以顺序遍历对象

#### DiscontinuousSpace（不连续空间）

```
TYPE  REGION                    ADDRESS             NAME
 7    [0x13000000, 0x14000000)  0x75db0d608900     large object space
```

**类型枚举**：
- `7`: LargeObjectSpace - 存储大对象（通常 > 12KB）

**特点**：
- 通过 `LargeObjectMap` 管理
- 需要特殊处理才能获取地址范围

### 五、关键技术点

#### 5.1 ANSI 颜色编码

```cpp
ANSI_COLOR_LIGHTRED     // 表头（红色）
ANSI_COLOR_LIGHTCYAN    // 地址范围（青色）
ANSI_COLOR_LIGHTYELLOW  // Space 对象地址（黄色）
ANSI_COLOR_LIGHTGREEN   // 空间名称（绿色）
ANSI_COLOR_RESET        // 重置颜色
```

这使得输出更易读，便于快速识别不同信息。

#### 5.2 对象遍历机制

`Android::ForeachObjects()` 的内部实现（参考 `android/android.cpp`）：

```cpp
void ForeachObjects(callback, flags, check) {
    art::gc::Heap& heap = art::Runtime::Current().GetHeap();

    // 遍历每个空间
    for (auto& space : heap.GetContinuousSpaces()) {
        // 根据 flags 过滤空间类型
        if (shouldIncludeSpace(space, flags)) {
            try {
                // 调用 Space::Walk() 遍历该空间的所有对象
                space->Walk([&](Object& obj) {
                    if (check && !obj.IsValid()) return;
                    callback(obj);
                });
            } catch (InvalidAddressException& e) {
                // 捕获异常，继续处理其他空间
                LOGW("Space %s walking interrupted", space->GetName());
            }
        }
    }

    // 类似处理 DiscontinuousSpaces
}
```

#### 5.3 验证策略

```cpp
class JavaVerify {
    // CHECK_FULL_BAD_OBJECT: 验证对象字段引用
    void verifyObject(Object& obj) {
        Class klass = obj.GetClass();
        // 遍历所有字段
        for (ArtField& field : klass.GetFields()) {
            if (field.IsPrimitiveType()) continue;

            // 读取引用字段
            uint32_t ref = obj.GetFieldObject(field.offset());
            Object referenced(ref);

            // 检查引用有效性
            if (ref != 0 && !referenced.IsValid()) {
                LOGE("Bad reference in field %s @ offset %u", 
                     field.GetName(), field.offset());
            }
        }
    }

    // CHECK_FULL_CONFLICT_METHOD: 检查方法冲突
    void verifyMethods() {
        // 检查 vtable/itable 中的方法冲突
        // 检查 IMT (Interface Method Table) 冲突
    }
};
```

### 六、使用示例

#### 示例 1: 显示所有空间

```bash
core-parser> space
TYPE   REGION                  ADDRESS             NAME
  5  [0x12c00000, 0x2ac00000)  0x75db0d608820  main space (region space)
  0  [0x70209000, 0x7033d840)  0x75dbad608430  /system/framework/x86_64/boot.art
  1  [0x0, 0x0)                0x75db0d6088e0  zygote space
  7  [0x13000000, 0x14000000)  0x75db0d608900  large object space
```

#### 示例 2: 只显示应用堆

```bash
core-parser> space --app
TYPE   REGION                  ADDRESS             NAME
  5  [0x12c00000, 0x2ac00000)  0x75db0d608820  main space (region space)
```

#### 示例 3: 检查应用对象完整性

```bash
core-parser> space --check --app
ERROR: Region:[0x12c00000, 0x12c00018) main space has bad object!!
  Object @ 0x12c00000: klass_ = 0x0 (invalid)
```

#### 示例 4: 完整验证

```bash
core-parser> space --full-check
Checking objects...
✓ Checked 1,234,567 objects
✗ Found 3 bad references
✗ Found 1 method conflict in Class 'java.util.HashMap'
```

### 七、设计亮点

1. **双模式设计**：显示和验证模式分离，职责清晰
2. **子进程隔离**：`ONCHLD` 避免崩溃影响主 REPL
3. **灵活过滤**：支持按空间类型过滤对象
4. **异常安全**：`ForeachObjects` 内部捕获异常，单个空间损坏不影响其他空间
5. **颜色编码**：ANSI 颜色提升可读性
6. **类型特化**：对 `LargeObjectSpace` 特殊处理获取地址范围

### 八、与其他命令的关系

```
space 命令
   ↓ 提供空间信息
class 命令 ← 使用 ForeachObjects 遍历对象
   ↓ 过滤特定类
top 命令 ← 统计对象分配
   ↓ 按空间分类
```

---

**总结**：`space` 命令是一个简洁但功能强大的工具，通过直接访问 ART Runtime 的 Heap 结构，展示内存布局并验证对象完整性。其设计体现了项目的核心理念：**通过镜像 AOSP 内部结构实现离线分析**。

**知识来源**: [知识来源: cmd_space.cpp 源码分析 + docs/exploration/ 知识文档]

