## 三、核心机制：ForeachObjects 堆遍历

### 3.1 顶层入口

```cpp
// android/android.cpp
void Android::ForeachObjects(
    std::function<bool (art::mirror::Object& object)> fn,
    int flag,    // 对象类型过滤标志
    bool check   // 是否验证对象有效性
) {
    art::Runtime& runtime = art::Runtime::Current();
    art::gc::Heap& heap = runtime.GetHeap();

    // 定义遍历函数
    auto walkfn = [&](art::gc::space::Space* space) {
        try {
            // 遍历该空间的所有对象
            space->Walk([&](art::mirror::Object& object) {
                // 可选：验证对象有效性
                if (check && !object.IsValid())
                    return;

                // 调用用户回调
                if (fn(object))
                    throw art::StopIteratorException();
            });
        } catch(InvalidAddressException& e) {
            LOGW("Space %s walking interrupted\n", space->GetName());
        } catch(art::StopIteratorException& e) {
            throw e;  // 用户主动停止遍历
        }
    };

    // 遍历连续空间（ContinuousSpace）
    for (const auto& space : heap.GetContinuousSpaces()) {
        if (space->IsImageSpace()) {
            if (flag & EACH_IMAGE_OBJECTS) walkfn(space.get());
        } else if (space->IsZygoteSpace()) {
            if (flag & EACH_ZYGOTE_OBJECTS) walkfn(space.get());
        } else if (space->IsRegionSpace() || space->IsBumpPointerSpace()) {
            if (flag & EACH_APP_OBJECTS) walkfn(space.get());
        } else if (space->IsMallocSpace()) {
            if (space->IsRosAllocSpace() || space->IsDlMallocSpace()) {
                if (flag & EACH_APP_OBJECTS) walkfn(space.get());
            }
        } else if (space->IsFakeSpace()) {
            if (flag & EACH_FAKE_OBJECTS) walkfn(space.get());
        }
    }

    // 遍历不连续空间（DiscontinuousSpace - 大对象空间）
    for (const auto& space : heap.GetDiscontinuousSpaces()) {
        if (flag & EACH_APP_OBJECTS) walkfn(space.get());
    }
}
```

### 3.2 Space::Walk() - 单个空间遍历

```cpp
// android/art/runtime/gc/space/space.cpp
void ContinuousSpace::Walk(std::function<void (Object&)> callback) {
    uint64_t begin = Begin();  // 空间起始地址
    uint64_t end = End();      // 空间结束地址

    // 按 8 字节对齐遍历（kObjectAlignment = 8）
    uint64_t current = begin;

    while (current < end) {
        try {
            // 1. 创建 Object 对象
            art::mirror::Object obj(current);

            // 2. 验证对象有效性
            if (!obj.IsValid()) {
                // 对象无效，跳到下一个可能的位置
                current = obj.NextValidOffset();
                continue;
            }

            // 3. 调用回调函数
            callback(obj);

            // 4. 移动到下一个对象
            uint32_t obj_size = obj.SizeOf();
            current += RoundUp(obj_size, kObjectAlignment);

        } catch(InvalidAddressException& e) {
            // 内存访问失败，尝试跳过
            current += kObjectAlignment;
        }
    }
}
```

**关键点**：
- **8 字节对齐**：所有对象按 8 字节边界对齐
- **对象大小计算**：`SizeOf()` 多态方法，根据对象类型计算大小
- **异常恢复**：单个对象访问失败不影响整体遍历

