## 五、PrintClass 回调：过滤和输出

```cpp
bool ClassCommand::PrintClass(art::mirror::Object& object, const char* classname) {
    // 1. 过滤：只处理 Class 对象
    if (!object.IsClass())
        return false;

    // 2. 转换为 Class 对象
    art::mirror::Class thiz = object;

    // 3. 模式判断
    if (options.dump_all) {
        // dump_all 模式：列出所有类
        options.total_classes++;
        LOGI("[%" PRId64 "] 0x%" PRIx64 " %s\n",
             options.total_classes, 
             thiz.Ptr(), 
             thiz.PrettyDescriptor().c_str());

        // 如果设置了显示选项，打印详细信息
        if (options.show_flag) 
            PrintPrettyClassContent(thiz, options);

    } else if (thiz.PrettyDescriptor() == classname) {
        // 搜索模式：类名匹配时打印
        PrintPrettyClassContent(thiz, options);
    }

    return false;  // 继续遍历
}
