## 二、命令入口：prepare() 和 main()

### 2.1 参数解析（prepare）

```cpp
int ClassCommand::prepare(int argc, char* const argv[]) {
    // 1. 前置检查
    if (!CoreApi::IsReady() || !Android::IsSdkReady())
        return Command::FINISH;

    // 2. 初始化选项
    options.dump_all = true;           // 是否列出所有类
    options.show_flag = 0;             // 显示选项标志
    options.format_hex = false;        // 是否十六进制显示
    options.obj_each_flags = 0;        // 对象类型过滤
    options.total_classes = 0;         // 类计数器

    // 3. 解析命令行参数
    while ((opt = getopt_long(argc, argv, "msifx", long_options, ...)) != -1) {
        switch (opt) {
            case 'm': options.show_flag |= SHOW_METHOD;    // 显示方法
            case 's': options.show_flag |= SHOW_STATIC;    // 显示静态字段
            case 'i': options.show_flag |= SHOW_IMPL;      // 显示实现的接口
            case 'f': options.show_flag |= SHOW_FIELD;     // 显示实例字段
            case 'x': options.format_hex = true;           // 十六进制格式
            case 1:   options.obj_each_flags |= EACH_APP_OBJECTS;     // 应用对象
            case 2:   options.obj_each_flags |= EACH_ZYGOTE_OBJECTS;  // Zygote 对象
            case 3:   options.obj_each_flags |= EACH_IMAGE_OBJECTS;   // Image 对象
            case 4:   options.obj_each_flags |= EACH_FAKE_OBJECTS;    // 伪造对象
        }
    }

    // 4. 默认行为：遍历所有类型的对象
    if (!options.obj_each_flags) {
        options.obj_each_flags = EACH_APP_OBJECTS | EACH_ZYGOTE_OBJECTS 
                               | EACH_IMAGE_OBJECTS | EACH_FAKE_OBJECTS;
    }

    // 5. 如果有参数（类名或地址），则不是 dump_all 模式
    if (options.optind < argc) {
        options.dump_all = false;
        options.show_flag = !options.show_flag ? SHOW_ALL : options.show_flag;
    }

    // 6. 准备 Android 运行时
    Android::Prepare();

    // 7. 在子进程执行（避免崩溃）
    return Command::ONCHLD;
}
