## 六、PrintPrettyClassContent：详细信息输出

```cpp
void ClassCommand::PrintPrettyClassContent(Class& clazz, Options& options) {
    // ========== 1. 类声明 ==========
    Class super = clazz.GetSuperClass();
    if (super.Ptr()) {
        LOGI("%s class %s extends %s {\n",
             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
             clazz.PrettyDescriptor().c_str(),
             super.PrettyDescriptor().c_str());
    } else {
        LOGI("%s class %s {\n", 
             PrettyClassAccessFlags(clazz.GetAccessFlags()).c_str(),
             clazz.PrettyDescriptor().c_str());
    }

    // ========== 2. 实现的接口 ==========
    if (options.show_flag & SHOW_IMPL) {
        IfTable& iftable = clazz.GetIfTable();
        int32_t ifcount = iftable.Count();

        if (ifcount > 0) {
            LOGI("  // Implements:\n");
            for (int i = 0; i < ifcount; ++i) {
                Class interface = iftable.GetInterface(i);
                LOGI("    %s\n", interface.PrettyDescriptor().c_str());
            }
        }
    }

    // ========== 3. 静态字段 ==========
    if (options.show_flag & SHOW_STATIC) {
        if (clazz.NumStaticFields() > 0) {
            LOGI("  // Class static fields:\n");

            // 收集所有静态字段
            std::vector<ArtField> fields;
            Android::ForeachStaticField(clazz, [&](ArtField& field) {
                fields.push_back(field);
                return false;
            });

            // 按偏移排序
            std::sort(fields.begin(), fields.end(), ArtField::Compare);

            // 打印每个静态字段
            for (auto& field : fields) {
                PrintCommand::PrintField(format, clazz, clazz, field, options);
            }
        }
    }

    // ========== 4. 实例字段（包括继承的） ==========
    if (options.show_flag & SHOW_FIELD) {
        LOGI("  // Object instance fields:\n");

        Class current = clazz;
        do {
            // 打印当前类的字段
            if (current != clazz) {
                LOGI("  // extends %s\n", current.PrettyDescriptor().c_str());
            }

            std::vector<ArtField> fields;
            Android::ForeachInstanceField(current, [&](ArtField& field) {
                fields.push_back(field);
                return false;
            });

            std::sort(fields.begin(), fields.end(), ArtField::Compare);

            for (auto& field : fields) {
                LOGI("    [0x%03x] %s %s %s\n",
                     field.offset(),
                     PrettyFieldAccessFlags(field.access_flags()).c_str(),
                     field.PrettyTypeDescriptor().c_str(),
                     field.GetName());
            }

            // 向上遍历继承链
            current = current.GetSuperClass();
        } while (current.Ptr());
    }

    // ========== 5. 方法 ==========
    if (options.show_flag & SHOW_METHOD) {
        if (clazz.NumMethods() > 0) {
            LOGI("  // Methods:\n");

            Android::ForeachArtMethods(clazz, [](ArtMethod& method) {
                LOGI("    [0x%" PRIx64 "] %s %s\n",
                     method.Ptr(),
                     PrettyMethodAccessFlags(method.access_flags()).c_str(),
                     method.ColorPrettyMethod().c_str());
                return false;
            });
        }
    }

    LOGI("}\n");
}
```

