                    retry--;
                    instptr++;
                    continue;
                }

                uint32_t rd = (inst & 0x1F);
                uint32_t opc = (inst >> 29) & 0b11;

                if (rd != 0x0 || opc != 0b10) {
                    retry--;
                    instptr++;
                    continue;
