/**
 * Claude Code Plugin: Knowledge Management
 * 管理知识文档的插件命令
 */

const { exec } = require('child_process');
const { promisify } = require('util');

const execAsync = promisify(exec);

module.exports = async function knowledge(args, context) {
  const { workspace, log } = context;
  const projectRoot = workspace.rootPath;

  // 解析参数
  const [action, ...params] = args;

  if (!action) {
    log.info('Knowledge Management Commands:');
    log.info('');
    log.info('  /knowledge list              - 列出所有文档');
    log.info('  /knowledge add <num> <title> <file>  - 添加新文档');
    log.info('  /knowledge update            - 更新索引');
    log.info('  /knowledge check             - 检查完整性');
    log.info('');
    log.info('Quick start:');
    log.info('  /init-explore                - 一键初始化并探索');
    return;
  }

  try {
    let command;

    switch (action) {
      case 'list':
        command = './scripts/update-knowledge.sh list';
        break;

      case 'add':
        if (params.length < 3) {
          log.error('用法: /knowledge add <num> <title> <file>');
          log.error('示例: /knowledge add 05 "性能优化" 05-performance.md');
          return;
        }
        command = `./scripts/update-knowledge.sh add ${params.join(' ')}`;
        break;

      case 'update':
        command = './scripts/update-knowledge.sh update';
        break;

      case 'check':
        command = './scripts/update-knowledge.sh check';
        break;

      default:
        log.error(`未知命令: ${action}`);
        log.info('运行 /knowledge 查看帮助');
        return;
    }

    log.info(`执行: ${command}`);
    const result = await execAsync(command, { cwd: projectRoot });

    log.info(result.stdout);
    if (result.stderr) {
      log.warn(result.stderr);
    }

    return {
      success: true,
      output: result.stdout
    };

  } catch (error) {
    log.error('❌ 错误: ' + error.message);
    return {
      success: false,
      error: error.message
    };
  }
};

